// 带编码类型定义
export interface ProvinceCode {
  c: string;  // code (2位)
  n: string;  // name
}

export interface CityCode {
  c: string;  // code (4位)
  n: string;  // name
  p: string;  // provinceCode (2位)
}

export interface CountyCode {
  c: string;   // code (6位或12位)
  n: string;   // name
  cc: string;  // cityCode (4位)
}

// 带编码层级结构
export interface PCACodeItem {
  c: string;
  n: string;
  ch?: PCACodeItem[];
}

export interface PCCodeItem {
  c: string;
  n: string;
  ch?: Omit<PCACodeItem, 'ch'>[];
}

// 不带编码类型
export type ProvinceList = string[];
export type CityList = string[];
export type CountyList = string[];

// 层级关系类型
export type PCA = Record<string, Record<string, string[]>>;
export type PC = Record<string, Record<string, 1>>;

// Cascader 类型
export interface CascaderOption {
  label: string;
  value: string;
  children?: CascaderOption[];
}

export interface CascaderOptionWithCode {
  label: string;
  value: string;
  code: string;
  children?: CascaderOptionWithCode[];
}

export interface CascaderOptionPC {
  label: string;
  value: string;
  children?: Array<{ label: string; value: string }>;
}

/** 统一地址值接口 */
export interface AddressValue {
  province: { name: string; code: string };
  city: { name: string; code: string };
  county: { name: string; code: string };
}

// ── 数据导出 ──

/** 带编码数据 */
export const provinces: ProvinceCode[];
export const cities: CityCode[];
export const counties: CountyCode[];
export const pcaCode: PCACodeItem[];
export const pcCode: PCCodeItem[];
export const provincesCode: ProvinceCode[];
export const citiesCode: CityCode[];
export const countiesCode: CountyCode[];

/** 不带编码数据 */
export const provincesNoCode: ProvinceList;
export const citiesNoCode: CityList;
export const countiesNoCode: CountyList;
export const pca: PCA;
export const pc: PC;

// ── 常量 ──

export const MUNICIPALITY_CODES: string[];
export const VERSION: string;

// ── Cascader 数据函数 ──

/** 三级 Cascader（带编码） */
export function getCascaderDataWithCode(): CascaderOption[];
/** 三级 Cascader（不带编码） */
export function getCascaderData(): CascaderOption[];
/** 二级省市 Cascader（带编码） */
export function getCascaderPCWithCode(): CascaderOptionPC[];


// ── 查询工具函数 ──

export function getProvinceByCode(code: string): ProvinceCode | undefined;
export function getCityByCode(code: string): CityCode | undefined;
export function getCountyByCode(code: string): CountyCode | undefined;
export function getNameByCode(code: string): string | undefined;
export function getAddressValueFromCodes(
  provinceCode: string | number,
  cityCode: string | number,
  countyCode: string | number
): AddressValue | null;

export function getCitiesByProvince(provinceCode: string): CityCode[];
export function getCountiesByCity(cityCode: string): CountyCode[];
export function isMunicipalityCode(code: string): boolean;
export function validateCode(code: string): boolean;
export function formatFullPath(code: string): string;
export function parseAddress(address: string): {
  province?: string;
  city?: string;
  county?: string;
  rest?: string;
} | null;

// ── 默认导出 ──

declare const _default: {
  pca: PCA; pc: PC;
  provinces: ProvinceCode[]; cities: CityCode[]; counties: CountyCode[];
  provincesNoCode: ProvinceList; citiesNoCode: CityList; countiesNoCode: CountyList;
  pcaCode: PCACodeItem[]; provincesCode: ProvinceCode[]; citiesCode: CityCode[]; countiesCode: CountyCode[];
  getCascaderDataWithCode: typeof getCascaderDataWithCode;
  getCascaderData: typeof getCascaderData;
  getCascaderPCWithCode: typeof getCascaderPCWithCode;
  getProvinceByCode: typeof getProvinceByCode;
  getCityByCode: typeof getCityByCode;
  getCountyByCode: typeof getCountyByCode;
  getNameByCode: typeof getNameByCode;
  getAddressValueFromCodes: typeof getAddressValueFromCodes;
  getCitiesByProvince: typeof getCitiesByProvince;
  getCountiesByCity: typeof getCountiesByCity;
  isMunicipalityCode: typeof isMunicipalityCode;
  validateCode: typeof validateCode;
  formatFullPath: typeof formatFullPath;
  parseAddress: typeof parseAddress;
  MUNICIPALITY_CODES: string[];
  VERSION: string;
};
export default _default;
